+        let mut bound_violations = 0;
+
+        for trial in 0..n_trials {
+            let mut sketch = CountMinSketch::new(config.clone());
+            let mut true_counts = std::collections::HashMap::new();
+
+            let mut rng_state = trial as u64 * 12345 + 1;
