+        assert_eq!(agg.stats.change_points_detected, 0);
+    }
+
+    #[test]
+    fn default_config_valid() {
+        let config = AggregatorConfig::default();
+        let agg = TimelineAggregator::new(config);
+        assert_eq!(agg.observation_count, 0);
